export const meta = {
  name: 'trivial-fanout',
  description: 'Fan out 3 parallel agents, each doing a trivial task then sleeping 20 seconds',
  phases: [
    { title: 'Fan-out', detail: '3 agents: trivial task + sleep 20' },
  ],
}
phase('Fan-out')
const results = await parallel([1, 2, 3].map(i => () =>
  agent(
    `You are agent #${i}. Do one trivial task: compute ${i} + ${i} and state the result. Then run exactly \`sleep 20\` using the Bash tool and wait for it to finish. Finally return a one-line summary like "agent ${i}: ${i}+${i}=<result>, slept 20s".`,
    { label: `trivial-${i}`, phase: 'Fan-out' }
  )
))
return { results: results.filter(Boolean) }
